:root {
  color-scheme: dark;
  --relay-font-sans:
    Inter, "DM Sans", ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
  --relay-font-mono: "SF Mono", "SFMono-Regular", Consolas, "Liberation Mono", Menlo, monospace;
  --relay-bg: #0a0a09;
  --relay-chrome: #0d0d0c;
  --relay-sidebar: #11110f;
  --relay-surface: #151512;
  --relay-surface-2: #191916;
  --relay-surface-3: #20201c;
  --relay-surface-hover: #23231f;
  --relay-surface-active: #2a2925;
  --relay-popover: #181815;
  --relay-input: #121210;
  --relay-text: #f0eee7;
  --relay-text-muted: #aaa49a;
  --relay-text-subtle: #7f786e;
  --relay-text-inverse: #ffffff;
  --relay-border-soft: rgb(255 255 255 / 5%);
  --relay-border: rgb(255 255 255 / 8%);
  --relay-border-strong: rgb(255 255 255 / 14%);
  --relay-primary: #D82927;
  --relay-primary-hover: #C92422;
  --relay-primary-active: #B8201F;
  --relay-primary-muted: rgb(216 41 39 / 14%);
  --relay-primary-text: #F05B55;
  --relay-ring: #D82927;
  --relay-info: #8fb8ff;
  --relay-info-muted: rgb(143 184 255 / 14%);
  --relay-success: #87d38b;
  --relay-success-muted: rgb(135 211 139 / 13%);
  --relay-warning: #e7c36a;
  --relay-warning-muted: rgb(231 195 106 / 14%);
  --relay-danger: #ff8f80;
  --relay-danger-muted: rgb(255 143 128 / 14%);
  --relay-info-text: #b5ccff;
  --relay-success-text: #a7dfa9;
  --relay-warning-text: #f3d78c;
  --relay-danger-text: #ffb1a7;
  --relay-radius-xs: 4px;
  --relay-radius-sm: 6px;
  --relay-radius-md: 8px;
  --relay-radius-lg: 10px;
  --relay-space-1: 4px;
  --relay-space-2: 8px;
  --relay-space-3: 12px;
  --relay-space-4: 16px;
  --relay-space-5: 20px;
  --relay-space-6: 24px;
  --relay-text-xs: 11px;
  --relay-text-sm: 12px;
  --relay-text-md: 13px;
  --relay-text-base: 14px;
  --relay-text-lg: 16px;
  --relay-text-xl: 20px;
  --relay-shadow-sm: 0 1px 2px rgb(0 0 0 / 24%);
  --relay-shadow-panel: 0 16px 48px rgb(0 0 0 / 26%);
  --relay-shadow-modal: 0 28px 90px rgb(0 0 0 / 46%);
  --relay-inset-highlight: inset 0 1px 0 rgb(255 255 255 / 5%);
  --relay-focus-ring: 0 0 0 2px var(--relay-bg), 0 0 0 4px var(--relay-ring);
  font-family: var(--relay-font-sans);
  background: var(--relay-bg);
  color: var(--relay-text);
  font-synthesis: none;
  text-rendering: optimizeLegibility;
}

* {
  box-sizing: border-box;
}

html,
body,
#root {
  width: 100%;
  height: 100%;
}

body {
  margin: 0;
  min-width: 0;
  min-height: 0;
  overflow: hidden;
  background: linear-gradient(180deg, var(--relay-chrome) 0%, var(--relay-bg) 46%);
}

button,
input,
textarea,
select {
  font: inherit;
}

button {
  min-height: 32px;
  border: 1px solid var(--relay-border);
  border-radius: var(--relay-radius-md);
  background: var(--relay-surface-2);
  color: var(--relay-text);
  padding: 0 11px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: var(--relay-space-2);
  cursor: pointer;
  box-shadow: var(--relay-inset-highlight);
  transition:
    background-color 140ms ease,
    border-color 140ms ease,
    color 140ms ease,
    box-shadow 140ms ease,
    transform 90ms ease;
}

button:hover {
  border-color: var(--relay-border-strong);
  background: var(--relay-surface-hover);
}

button:active {
  transform: translateY(1px);
  background: var(--relay-surface-active);
  box-shadow: none;
}

button:focus-visible,
input:focus-visible,
textarea:focus-visible,
select:focus-visible {
  outline: none;
  box-shadow: var(--relay-focus-ring);
}

button:disabled {
  cursor: not-allowed;
  opacity: 0.52;
  transform: none;
}

button svg {
  flex: 0 0 auto;
  opacity: 0.86;
}

input,
textarea,
select {
  width: 100%;
  border: 1px solid var(--relay-border);
  border-radius: var(--relay-radius-md);
  background: var(--relay-input);
  color: var(--relay-text);
  padding: 8px 10px;
  outline: none;
  box-shadow: var(--relay-inset-highlight);
  transition:
    background-color 140ms ease,
    border-color 140ms ease,
    box-shadow 140ms ease;
}

input::placeholder,
textarea::placeholder {
  color: var(--relay-text-subtle);
}

input:hover,
textarea:hover,
select:hover {
  border-color: var(--relay-border-strong);
}

textarea {
  min-height: 132px;
  resize: vertical;
  line-height: 1.45;
}

select {
  color: var(--relay-text);
}

option {
  background: var(--relay-popover);
  color: var(--relay-text);
}

pre,
code {
  font-family: var(--relay-font-mono);
}

::-webkit-scrollbar {
  width: 8px;
  height: 8px;
}

::-webkit-scrollbar-track {
  background: transparent;
}

::-webkit-scrollbar-thumb {
  border: 2px solid transparent;
  border-radius: 999px;
  background: rgb(255 255 255 / 18%);
  background-clip: padding-box;
}

::-webkit-scrollbar-thumb:hover {
  background: rgb(255 255 255 / 28%);
  background-clip: padding-box;
}

.app-shell {
  display: grid;
  grid-template-columns: 272px minmax(0, 1fr);
  height: 100dvh;
  min-width: 0;
  overflow: hidden;

