const pairs = [
  ['primary button', '#ffffff', '#9F1D1B'],
  ['primary hover', '#ffffff', '#B32623'],
  ['primary active', '#ffffff', '#841715'],
  ['primary text on app bg', '#D96760', '#0a0a09'],
  ['primary text on surface', '#D96760', '#151512'],
  ['primary text on raised surface', '#D96760', '#20201c'],
  ['focus ring on app bg', '#B83A34', '#0a0a09'],
  ['focus ring on input bg', '#B83A34', '#121210']
];
function lin(c) { c /= 255; return c <= 0.03928 ? c / 12.92 : Math.pow((c + 0.055) / 1.055, 2.4); }
function lum(hex) { const n = hex.replace('#',''); const r = parseInt(n.slice(0,2),16), g = parseInt(n.slice(2,4),16), b = parseInt(n.slice(4,6),16); return 0.2126 * lin(r) + 0.7152 * lin(g) + 0.0722 * lin(b); }
function contrast(a,b) { const x = lum(a), y = lum(b); const hi = Math.max(x,y), lo = Math.min(x,y); return (hi + 0.05) / (lo + 0.05); }
let failed = false;
for (const [label, a, b] of pairs) {
  const ratio = contrast(a,b);
  const threshold = label.includes('focus ring') ? 3 : 4.5;
  console.log("'`${label}: ${ratio.toFixed(2)}:1`);
  if (ratio < threshold) failed = true;
}
process.exit(failed ? 1 : 0);
NODE'

